  Map<string, number>
>(new Map());

const retryPane = useCallback((paneId: string) => {
  setPaneRetryCounters((prev) => {
    const next = new Map(prev);
    next.set(paneId, (prev.get(paneId) ?? 0) + 1);
    return next;
  });
}, []);

