  );
}

function StateBadge({ state }: { state: AlarmRow["state"] }) {
  const color =
    state === "active"
      ? "#EF4444"
      : state === "unacknowledged"
        ? "#F59E0B"
        : "var(--io-text-muted)";

  return (
    <span
      style={{
        fontSize: 12,
        color,
        fontWeight: state !== "acknowledged" ? 600 : 400,
      }}
    >
      {state === "active"
        ? "Active"
        : state === "unacknowledged"
          ? "Unack"
          : "Acked"}
    </span>
  );
}

